mapper.select:
SELECT

FROM sms_verification_codes
WHERE phone = #{phone}
  AND code = #{code}
  AND scene = #{scene}
  AND status = 0
  AND expire_time > NOW()
ORDER BY create_time DESC
LIMIT 1

SELECT COUNT(*)
FROM sms_verification_codes
WHERE phone = #{phone}
  AND create_time >= #{startTime}
  AND create_time <= #{endTime}

mapper.delete:
DELETE FROM sms_verification_codes
WHERE expire_time < #{expireTime}
  OR (status IN (1, 2) AND create_time < DATE_SUB(NOW(), INTERVAL 7 DAY))
